# -*- coding: utf-8 -*-
"""Generate a Vaporwave-themed single-page song list website for 岁己SUI. v2"""
import json, os

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
PROJECT_ROOT = os.path.dirname(SCRIPT_DIR)
DATA_DIR = os.path.join(PROJECT_ROOT, 'data')

with open(os.path.join(DATA_DIR, 'song_data.json'), 'r', encoding='utf-8') as f:
    data = json.load(f)

# Load Bilibili matching data and merge into songs
bili_map = {}
try:
    with open(os.path.join(DATA_DIR, 'song_bilibili_map.json'), 'r', encoding='utf-8') as f:
        bili_data = json.load(f)
        bili_map = bili_data.get('matches', {})
        print(f'Loaded {len(bili_map)} song-video matches')
except:
    print('No bilibili matching data found')

# Merge bili data into songs (compact format)
for song in data['songs']:
    clips = bili_map.get(song['name'], [])
    if clips:
        song['bili'] = [{'bv': c['bvid'], 't': c['title'], 'd': c.get('duration', 0), 'dt': c.get('date', '')} for c in clips]

# Load complete date list and enrich songs
date_lookup = {}
try:
    with open(os.path.join(DATA_DIR, 'sui_song_list_complete.json'), 'r', encoding='utf-8') as f:
        complete = json.load(f)
        for entry in complete:
            name = entry.get('song_name', '')
            date_str = entry.get('date_list', '')
            if name and date_str:
                # Parse "2022/9/4，2022/9/5，..." into sorted array
                dates = [d.strip().replace('/', '-') for d in date_str.replace('，', ',').split(',') if d.strip()]
                # Filter out garbage dates before 2022-09 (e.g. 1901-11-xx)
                dates = [d for d in dates if d.split('-')[0].isdigit() and int(d.split('-')[0]) >= 2022]
                dates.sort()
                if name in date_lookup:
                    date_lookup[name] = sorted(set(date_lookup[name] + dates))
                else:
                    date_lookup[name] = dates
    print(f'Loaded date lists for {len(date_lookup)} songs')
except Exception as e:
    print(f'Could not load complete date data: {e}')

for song in data['songs']:
    dates = date_lookup.get(song['name'], [])
    if dates:
        song['dates'] = dates

# Auto-calculate stats and lang_counts from songs array
songs = data['songs']
total = len(songs)
performances = sum(s.get('count', 0) for s in songs)
frequent = sum(1 for s in songs if s.get('count', 0) >= 5)
occasional = sum(1 for s in songs if 2 <= s.get('count', 0) < 5)
once = sum(1 for s in songs if s.get('count', 0) == 1)
data['stats'] = {'total': total, 'performances': performances, 'frequent': frequent, 'occasional': occasional, 'once': once}
lang_map = {}
for s in songs:
    lang = s.get('lang', '未知')
    lang_map[lang] = lang_map.get(lang, 0) + 1
data['lang_counts'] = sorted([{'lang': k, 'count': v} for k, v in lang_map.items()], key=lambda x: -x['count'])
print(f'Auto-calculated stats: {total} songs, {performances} performances, {frequent} frequent, {occasional} occasional, {once} once')

# Build dates lookup map (separate from SONGS to avoid attribute encoding issues)
dates_map = {}
for s in data['songs']:
    if s.get('dates'):
        # Filter out garbage dates before 2022
        valid = [d for d in s['dates'] if d.split('-')[0].isdigit() and int(d.split('-')[0]) >= 2022]
        if valid:
            dates_map[s['name']] = valid
        del s['dates']  # Removed from SONGS, served via SONG_DATES
dates_json = json.dumps(dates_map, ensure_ascii=False)
songs_json = json.dumps(data['songs'], ensure_ascii=False)
stats_json = json.dumps(data['stats'], ensure_ascii=False)
lang_json = json.dumps(data['lang_counts'], ensure_ascii=False)

